// Pull and clean the form submission
const form = $input.first().json;

// Build a clean, normalized call record from the form fields
const repName        = (form['Your Name']              || '').trim();
const repEmail       = (form['Your Email']             || '').trim().toLowerCase();
const company        = (form['Prospect Company Name']  || '').trim();
const contactName    = (form['Prospect Contact Name']  || '').trim();
const contactEmail   = (form['Prospect Email']         || '').trim().toLowerCase();
const dealStage      = (form['Current Deal Stage']     || 'Unknown').trim();
const dealValue      = parseFloat(form['Estimated Deal Value (USD)']) || null;
const audioUrl       = (form['Call Recording Direct Link'] || '').trim();
const durationMins   = parseInt(form['Call Duration (minutes)']) || 0;
const repNotes       = (form['Any notes before analysis?'] || '').trim();

// Basic checks
if (!repName || !repEmail)    throw new Error('Rep name and email are required.');
if (!company || !contactName) throw new Error('Prospect company and contact name are required.');
if (!audioUrl)                throw new Error('Audio recording link is required.');

const submissionId = 'CALL-' + Date.now();

return [{
  json: {
    submissionId,
    repName,
    repEmail,
    company,
    contactName,
    contactEmail,
    dealStage,
    dealValue,
    audioUrl,
    durationMins,
    repNotes,
    submittedAt: new Date().toISOString()
  }
}];

// Merge Whisper output with the original form data
const whisper  = $input.first().json;
const formData = $('2. Code — Clean and Validate Form Data').first().json;

if (!whisper || whisper.error) {
  throw new Error('Whisper transcription failed: ' + (whisper?.error?.message || 'Unknown error'));
}

const transcript = (whisper.text || '').trim();
if (!transcript) throw new Error('Transcription came back empty — audio may be silent or corrupted.');

const wordCount = transcript.split(/\s+/).filter(w => w).length;

return [{
  json: {
    ...formData,
    transcript,
    wordCount,
    transcribedAt: new Date().toISOString()
  }
}];

// Parse GPT-4o JSON response and merge everything
const gptResponse = $input.first().json;
const callData    = $('5. Code — Merge Transcript with Call Data').first().json;

const rawText = gptResponse?.choices?.[0]?.message?.content || gptResponse?.output || '';
if (!rawText) throw new Error('GPT-4o returned an empty response.');

const clean = rawText.replace(/```json\s*/gi, '').replace(/```/gi, '').trim();

let analysis;
try {
  analysis = JSON.parse(clean);
} catch (e) {
  throw new Error('Could not parse GPT-4o output as JSON. Raw: ' + clean.substring(0, 300));
}

return [{
  json: {
    submissionId:  callData.submissionId,
    repName:       callData.repName,
    repEmail:      callData.repEmail,
    company:       callData.company,
    contactName:   callData.contactName,
    contactEmail:  callData.contactEmail,
    dealStage:     callData.dealStage,
    dealValue:     callData.dealValue,
    durationMins:  callData.durationMins,
    wordCount:     callData.wordCount,
    submittedAt:   callData.submittedAt,
    analysis,
    processedAt:   new Date().toISOString()
  }
}];
